"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["35755"],{30561(i){i.exports=JSON.parse('{"tag":{"label":"career","permalink":"/sysanalyst-kb.github.io/docs/tags/career","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":10,"items":[{"id":"specialization/ai-analyst-intro","title":"AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438 \u0440\u043E\u043B\u044C","description":"AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u044D\u0442\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430\u0445 \u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0445 \u0441 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C. \u041E\u043D \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0441\u0431\u043E\u0440 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439 \u043A ML-\u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430\u043C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0434\u0430\u043D\u043D\u044B\u0445, \u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u043A\u0443 \u043C\u0435\u0442\u0440\u0438\u043A \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u043C\u043E\u0434\u0435\u043B\u0438 \u0438 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u0438\u0435 \u043E\u0436\u0438\u0434\u0430\u043D\u0438\u0439 \u043C\u0435\u0436\u0434\u0443 \u0431\u0438\u0437\u043D\u0435\u0441\u043E\u043C \u0438 Data Science \u043A\u043E\u043C\u0430\u043D\u0434\u043E\u0439.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-analyst-intro"},{"id":"specialization/ecommerce-retail-path","title":"E-commerce & Retail \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"E-commerce-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043E\u043D\u043B\u0430\u0439\u043D-\u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C\u0438 Wildberries, Ozon, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u043A\u0435\u0442, AliExpress.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-retail-path"},{"id":"specialization/fintech-analyst-path","title":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u043D\u0430 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0445 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430\u0445: \u043F\u043B\u0430\u0442\u0435\u0436\u0430\u0445, \u0431\u0430\u043D\u043A\u0438\u043D\u0433\u0435, \u043A\u0440\u0435\u0434\u0438\u0442\u043E\u0432\u0430\u043D\u0438\u0438. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \xab\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E\xbb SA, \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0443 (\u0426\u0411, KYC/AML, PCI DSS), \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B (ISO 8583, ISO 20022) \u0438 \u0431\u0443\u0445\u0433\u0430\u043B\u0442\u0435\u0440\u0441\u043A\u0438\u0439 \u0443\u0447\u0451\u0442 (double-entry ledger). \u042D\u0442\u043E \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0432\u044B\u0441\u043E\u043A\u043E\u043E\u043F\u043B\u0430\u0447\u0438\u0432\u0430\u0435\u043C\u044B\u0445 \u043D\u0438\u0448 \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-analyst-path"},{"id":"specialization/gamedev-path","title":"GameDev \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u0432 \u0433\u0435\u0439\u043C\u0434\u0435\u0432\u0435","description":"GameDev-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u043C\u043E\u0441\u0442 \u043C\u0435\u0436\u0434\u0443 \u0433\u0435\u0439\u043C-\u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0430\u043C\u0438, \u043F\u0440\u043E\u0434\u0430\u043A\u0442-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440\u0430\u043C\u0438 \u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u043E\u0439. \u0420\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0431\u0430\u043B\u0430\u043D\u0441\u0430\u043C\u0438, \u043C\u0430\u0442\u0447\u043C\u0435\u0439\u043A\u0438\u043D\u0433\u043E\u043C, \u043C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u0435\u0439 (IAP, \u0440\u0435\u043A\u043B\u0430\u043C\u0430), LiveOps (\u0438\u0432\u0435\u043D\u0442\u044B, \u0431\u043E\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0430), \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0430\u043C\u0438 \u0438 \u0438\u0433\u0440\u043E\u0432\u043E\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u043E\u0439. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u043A\u043E\u0440\u043F\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0439 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0432 \u0438\u0433\u0440\u0430\u0445 \u043A\u0440\u0438\u0442\u0438\u0447\u043D\u044B: real-time \u0441\u0435\u0441\u0441\u0438\u0438, \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u044B \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439, \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \xab\u0437\u0430\u043C\u043A\u043D\u0443\u0442\u044B\u0435 \u0446\u0438\u043A\u043B\u044B\xbb \u0438 A/B-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-path"},{"id":"specialization/govtech-path","title":"GovTech \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435","description":"GovTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 (\u0413\u0418\u0421) \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (\u0424\u0421\u0422\u042D\u041A, 152-\u0424\u0417, 44-\u0424\u0417), \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435, \u0434\u043B\u0438\u043D\u043D\u044B\u0435 \u0442\u0435\u043D\u0434\u0435\u0440\u043D\u044B\u0435 \u0446\u0438\u043A\u043B\u044B \u0438 \u0440\u0430\u0431\u043E\u0442\u0430 \u0441 \u0413\u0418\u0421-\u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438. \u0420\u044B\u043D\u043E\u043A GovTech \u0432 \u0420\u0424 \u2014 350+ \u043C\u043B\u0440\u0434 \u20BD (2024), CAGR 25%, \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0434\u0440\u0430\u0439\u0432\u0435\u0440 \u2014 \u0446\u0438\u0444\u0440\u043E\u0432\u0430\u044F \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433 \u0438 \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-path"},{"id":"specialization/medtech-path","title":"MedTech \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0432 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0435 \u0438 \u0444\u0430\u0440\u043C\u0435","description":"MedTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (323-\u0424\u0417, 152-\u0424\u0417, \u043E\u0431\u043E\u0440\u043E\u0442 \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432), \u0441\u043B\u043E\u0436\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 (HL7 FHIR, DICOM), \u0432\u044B\u0441\u043E\u043A\u0438\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u041F\u0414 \u0438 \u0440\u0430\u0431\u043E\u0442\u0430 \u0441 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E \u0432\u0430\u0436\u043D\u044B\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u043E\u0432. \u0420\u044B\u043D\u043E\u043A MedTech \u0432 \u0420\u0424 \u2014 150+ \u043C\u043B\u0440\u0434 \u0440\u0443\u0431/\u0433\u043E\u0434, \u0431\u043E\u043B\u0435\u0435 10 000 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0439 \u043D\u0443\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u0432 \u0446\u0438\u0444\u0440\u043E\u0432\u0438\u0437\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-path"},{"id":"specialization/telecom-path","title":"Telecom \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"Telecom-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 BSS/OSS \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0434\u043B\u044F \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u0430\u043C\u0438, \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0437\u0430\u043A\u0430\u0437\u0430\u043C\u0438 \u0438 \u0441\u0435\u0442\u044C\u044E. \u0421\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430: \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u044B \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u043E\u0432, real-time charging, \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (\u0421\u041E\u0420\u041C, 152-\u0424\u0417, \u043B\u0438\u0446\u0435\u043D\u0437\u0438\u0438) \u0438 \u0434\u043B\u0438\u043D\u043D\u044B\u0439 lifecycle (\u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u044F\u043C\u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0449\u0438\u0435 legacy-\u0441\u0438\u0441\u0442\u0435\u043C\u044B).","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-path"},{"id":"specialization/ba-vs-sa","title":"\u0411\u0438\u0437\u043D\u0435\u0441-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A vs \u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A","description":"\u041E\u0434\u0438\u043D \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0447\u0430\u0441\u0442\u044B\u0445 \u0432\u043E\u043F\u0440\u043E\u0441\u043E\u0432 \u043E\u0442 \u043D\u043E\u0432\u0438\u0447\u043A\u043E\u0432: \xab\u0427\u0435\u043C \u0431\u0438\u0437\u043D\u0435\u0441-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A (BA) \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 (SA)?\xbb \u0413\u0434\u0435 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0431\u043E\u0442\u0430 BA \u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0431\u043E\u0442\u0430 SA?","permalink":"/sysanalyst-kb.github.io/docs/specialization/ba-vs-sa"},{"id":"specialization/data-analyst-path","title":"\u041F\u0443\u0442\u044C Data-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"Data-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A (\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u0430\u043D\u043D\u044B\u0445) \u2014 \u044D\u0442\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0434\u0430\u043D\u043D\u044B\u043C\u0438: \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u0442, \u043E\u0447\u0438\u0449\u0430\u0435\u0442, \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0438 \u0432\u0438\u0437\u0443\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430, \u0444\u043E\u043A\u0443\u0441 \u043D\u0435 \u043D\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u0445 \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u0430 \u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u0445 \u0438 \u0432\u044B\u0432\u043E\u0434\u0430\u0445 \u0438\u0437 \u043D\u0438\u0445.","permalink":"/sysanalyst-kb.github.io/docs/specialization/data-analyst-path"},{"id":"specialization/solution-architect-path","title":"\u041F\u0443\u0442\u044C Solution-\u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u043E\u0440\u0430","description":"Solution Architect (SArch) \u2014 \u044D\u0442\u043E \u0440\u043E\u043B\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441 \u0438 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E. Solution Architect \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B: \u0432\u044B\u0431\u043E\u0440 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438, \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0441\u0442\u0438\u043B\u0438, \u043E\u0446\u0435\u043D\u043A\u0430 \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/solution-architect-path"}],"unlisted":false}}')}}]);